arguments.code:
import json
import urllib.request
import urllib.parse

# Let's try to query the articles_db with a regex for "World" category keywords.
# We can use the $regex operator in MongoDB.
# World keywords: "Iraq|Syria|UN|Obama|Putin|China|Russia|Europe|Africa|Asia|Middle East|war|peace|election|president|minister|government|military|troops|bomb|attack|terror|police|court|judge|law|protest|strike|union"
# Let's just query the count of articles matching these keywords for each region.
# Wait, we can't join MongoDB and SQLite in a single query.
# But we have the article_ids for each region in 2015 from SQLite.
# Let's group the article_ids by region.
region_article_ids = {}
for row in env['data_1']:
    region = row['region']
    if region not in region_article_ids:
        region_article_ids[region] = []
    region_article_ids[region].append(row['article_id'])

for region, ids in region_article_ids.items():
    print(f"{region}: {len(ids)} articles")

# Now we can query MongoDB for the count of articles matching "World" keywords for each region.
# We can use the $regex operator.
world_regex = "(?i)(Iraq|Syria|UN|Obama|Putin|China|Russia|Europe|Africa|Asia|Middle East|war|peace|election|president|minister|government|military|troops|bomb|attack|terror|police|court|judge|law|protest|strike|union)"

for region, ids in region_article_ids.items():
    query = [
        {"$match": {
            "article_id": {"$in": ids},
            "$or": [
                {"title": {"$regex": world_regex}},
                {"description": {"$regex": world_regex}}
            ]
        }},
        {"$count": "count"}
    ]
    env[f'query_{region}'] = json.dumps(query)
    print(f"Prepared query for {region}")

