import json
# The response is still too large.
# Let's query the count of articles matching the "World" regex for each region.
# We can do this by passing the regex to MongoDB and grouping by article_id, but we don't have region in MongoDB.
# We can query MongoDB for ALL article_ids that match the "World" regex, but only return the count.
# Wait, we need the count PER REGION.
# We can query the count of articles matching the "World" regex for each region separately.
# We can use the $in operator with the article_ids for each region.
# But the query string is too long for the tool.
# Let's split the article_ids for each region into smaller batches, query the count for each batch, and sum them up.
region_article_ids = {}
for row in env['data_1']:
    region = row['region']
    if region not in region_article_ids:
        region_article_ids[region] = []
    region_article_ids[region].append(row['article_id'])

world_regex = "(?i)(Iraq|Syria|UN|Obama|Putin|China|Russia|Europe|Africa|Asia|Middle East|war|peace|election|president|minister|government|military|troops|bomb|attack|terror|police|court|judge|law|protest|strike|union)"

batch_size = 500
queries = []
for region, ids in region_article_ids.items():
    batches = [ids[i:i + batch_size] for i in range(0, len(ids), batch_size)]
    for i, batch in enumerate(batches):
        query = [
            {"$match": {
                "article_id": {"$in": batch},
                "$or": [
                    {"title": {"$regex": world_regex}},
                    {"description": {"$regex": world_regex}}
                ]
            }},
            {"$count": "count"}
        ]
        queries.append((region, i, json.dumps(query)))

print(f"Prepared {len(queries)} queries.")
env['queries'] = queries

